struct GoogleMapView: UIViewRepresentable {
    @Binding var center: CLLocationCoordinate2D
    @Binding var selected: CLLocationCoordinate2D?

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition(latitude: center.latitude, longitude: center.longitude, zoom: 12)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = false
        mapView.delegate = context.coordinator

        context.coordinator.marker.map = mapView
        context.coordinator.marker.title = "Tap Location"
        return mapView
    }

    func updateUIView(_ mapView: GMSMapView, context: Context) {
        let cam = GMSCameraPosition(latitude: center.latitude, longitude: center.longitude, zoom: mapView.camera.zoom)
        mapView.animate(to: cam)

        if let sel = selected {
            context.coordinator.marker.position = sel
        } else {
            context.coordinator.marker.position = center
        }
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        var parent: GoogleMapView
        let marker = GMSMarker()

        init(_ parent: GoogleMapView) {
            self.parent = parent
            super.init()
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            parent.selected = coordinate
            marker.position = coordinate
            marker.snippet = String(format: "%.5f, %.5f", coordinate.latitude, coordinate.longitude)
        }
    }
}

