@MainActor
final class PaymentsDemoModel: ObservableObject {
    @Published var isLoading: Bool = false
    @Published var statusText: String = "Not started"
    @Published var statusColor: Color = .secondary

    private var paymentSheet: PaymentSheet?
    private var hasStripeKey: Bool = false

    var payButtonTitle: String {
        hasStripeKey ? "Present PaymentSheet" : "Stripe key missing"
    }

    var isPayDisabled: Bool {
        isLoading || !hasStripeKey
    }

    func refreshConfigurationState() {
        let key = STPAPIClient.shared.publishableKey ?? ""
        hasStripeKey = !key.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        if !hasStripeKey {
            statusText = "Missing Stripe publishable key. Add STRIPE_PUBLISHABLE_KEY in Info.plist."
            statusColor = .orange
        } else {
            statusText = "Ready (UI demo). Backend required for real payments."
            statusColor = .secondary
        }
    }

    func presentPaymentSheet() {
        guard hasStripeKey else { return }
        statusText = "Preparing PaymentSheet (demo)…"
        statusColor = .secondary
        isLoading = true

        // Demo-only: Create a PaymentSheet with placeholder configuration.
        // Real payments require:
        // - Fetch PaymentIntent client secret from your backend
        // - Optionally ephemeral key + customer id for saved methods
        let configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Investor Demo"
        configuration.allowsDelayedPaymentMethods = false

        // Without a PaymentIntent client secret, we can't present a real sheet.
        // We'll show a controlled message instead.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.4) {
            self.isLoading = false
            self.statusText = "Backend not configured. Provide a PaymentIntent client secret from your server to present PaymentSheet."
            self.statusColor = .red
        }
    }
}

